import { type Language, type Joke, jokesData } from "@/data/jokes";

const ENGLISH_API = "https://v2.jokeapi.dev/joke/Any?type=single&safe-mode";

/**
 * Fetches a joke for the given language.
 * - English: tries JokeAPI first, falls back to local pool.
 * - Regional: simulates an async DB call from the expanded local pool.
 *
 * @param lang        Target language code
 * @param viewedIds   Set of recently-viewed joke IDs to avoid repeats
 * @param maxRetries  How many times to re-draw if we get a duplicate
 */
export async function fetchJoke(
  lang: Language,
  viewedIds: Set<number>,
  maxRetries = 5
): Promise<Joke> {
  // ── English: try external API first ──
  if (lang === "en") {
    try {
      const res = await fetch(ENGLISH_API);
      const data = await res.json();
      if (res.ok && !data.error && data.joke) {
        const joke: Joke = { id: data.id, text: data.joke };
        if (!viewedIds.has(joke.id)) return joke;
        // If already viewed, fall through to local pool
      }
    } catch {
      // Network error → fall through to local pool
    }
  }

  // ── All languages: local pool with simulated async delay ──
  await simulateDelay(300 + Math.random() * 400);

  const pool = jokesData[lang];
  if (!pool || pool.length === 0) {
    return { id: -1, text: "No jokes available for this language." };
  }

  // Try to find a non-viewed joke
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    const joke = pool[Math.floor(Math.random() * pool.length)];
    if (!viewedIds.has(joke.id)) return joke;
  }

  // If all retries exhausted (pool smaller than history), return any random
  return pool[Math.floor(Math.random() * pool.length)];
}

function simulateDelay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}
